"use client"

import { useEffect, useState } from "react"
import { fetchPolicyEvaluation } from "@/lib/api"
import { t } from "@/i18n/es"

export default function Home() {

  const [data,setData] = useState<any>(null)

  useEffect(()=>{
    fetchPolicyEvaluation().then(setData)
  },[])

  if(!data){
    return (
      <main className="p-10">
        <h1 className="text-3xl font-bold">{t.title}</h1>
        <p className="mt-4 text-gray-400">{t.loading}</p>
      </main>
    )
  }

  return (

    <main className="p-10 space-y-10">

      <h1 className="text-4xl font-bold">{t.title}</h1>

      <section>
        <h2 className="text-xl font-semibold mb-2">{t.policy}</h2>
        <pre>{JSON.stringify(data.policy,null,2)}</pre>
      </section>

      <section>
        <h2 className="text-xl font-semibold mb-2">{t.metrics}</h2>
        <pre>{JSON.stringify(data.metrics,null,2)}</pre>
      </section>

      <section>
        <h2 className="text-xl font-semibold mb-2">{t.scenarios}</h2>
        <pre>{JSON.stringify(data.scenarios,null,2)}</pre>
      </section>

    </main>

  )

}
